  1	import * as _ from 'lodash-es';
  2	import * as React from 'react';
  3	import { Button, Level, LevelItem, Title } from '@patternfly/react-core';
  4	import MonacoEditor from 'react-monaco-editor';
  5	import { ChevronDownIcon } from '@patternfly/react-icons/dist/esm/icons/chevron-down-icon';
  6	import { ChevronRightIcon } from '@patternfly/react-icons/dist/esm/icons/chevron-right-icon';
  7	import { DownloadIcon } from '@patternfly/react-icons/dist/esm/icons/download-icon';
  8	import { PasteIcon } from '@patternfly/react-icons/dist/esm/icons/paste-icon';
  9	import { useTranslation } from 'react-i18next';
 10	import { referenceFor } from '../../utils/k8s-utils';
 11	import { Sample } from '../types';
 12	import { FirehoseResult, K8sKind } from '@openshift-console/dynamic-plugin-sdk';
 13	
 14	const ResourceSidebarSample: React.FC<ResourceSidebarSampleProps> = ({
 15	  sample,
 16	  loadSampleYaml,
 17	  downloadSampleYaml,
 18	}) => {
 19	  const { highlightText, title, img, description, id, yaml, targetResource } =
 20	    sample;
 21	  const reference = referenceFor(targetResource);
 22	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 23	  return (
 24	    <li className="co-resource-sidebar-item">
 25	      <Title headingLevel="h3" size="lg" className="pf-v6-u-mb-sm">
 26	        <span className="pf-v5-u-text-transform-uppercase">
 27	          {highlightText}
 28	        </span>{' '}
 29	        {title}
 30	      </Title>
 31	      {img && (
 32	        <img
 33	          src={img}
 34	          className="co-resource-sidebar-item__img img-responsive"
 35	        />
 36	      )}
 37	      <p>{description}</p>
 38	      <Level>
 39	        <LevelItem>
 40	          <Button
 41	            type="button"
 42	            variant="link"
 43	            data-test="load-sample"
 44	            isInline
 45	            onClick={() => loadSampleYaml(id, yaml, reference)}
 46	          >
 47	            <PasteIcon className="co-icon-space-r" />
 48	            {t('Try it')}
 49	          </Button>
 50	        </LevelItem>
 51	        <LevelItem>
 52	          <Button
 53	            type="button"
 54	            variant="link"
 55	            data-test="download-sample"
 56	            isInline
 57	            onClick={() => downloadSampleYaml(id, yaml, reference)}
 58	          >
 59	            <DownloadIcon className="co-icon-space-r" />
 60	            {t('Download YAML')}
 61	          </Button>
 62	        </LevelItem>
 63	      </Level>
 64	    </li>
 65	  );
 66	};
 67	
 68	const lineHeight = 18;
 69	const PreviewYAML = ({ maxPreviewLines = 20, yaml }) => {
 70	  return (
 71	    <div style={{ paddingTop: 10 }}>
 72	      <MonacoEditor
 73	        height={Math.min(yaml.split('\n').length, maxPreviewLines) * lineHeight}
 74	        language="yaml"
 75	        value={yaml}
 76	        theme="console-dark"
 77	        options={{
 78	          lineHeight,
 79	          readOnly: true,
 80	          folding: false,
 81	          minimap: { enabled: false },
 82	          scrollBeyondLastLine: false,
 83	        }}
 84	      />
 85	    </div>
 86	  );
 87	};
 88	
 89	interface ResourceSidebarSnippetProps {
 90	  snippet: Sample;
 91	  insertSnippetYaml: (id: string, yaml: string, reference: string) => void;
 92	}
 93	
 94	const ResourceSidebarSnippet: React.FC<ResourceSidebarSnippetProps> = ({
 95	  snippet,
 96	  insertSnippetYaml,
 97	}) => {
 98	  const {
 99	    highlightText,
100	    title,
101	    id,
102	    yaml,
103	    lazyYaml,
104	    targetResource,
105	    description,
106	  } = snippet;
107	
108	  const [yamlPreview, setYamlPreview] = React.useState<string>(yaml);
109	  const [yamlPreviewOpen, setYamlPreviewOpen] = React.useState(false);
110	
111	  const resolveYaml = async (callback: (resolvedYaml: string) => void) => {
112	    if (yaml) {
113	      callback(yaml);
114	    } else if (lazyYaml) {
115	      try {
116	        callback(await lazyYaml());
117	      } catch (error) {
118	        // eslint-disable-next-line no-console
119	        console.warn(
120	          `Error while running lazy yaml snippet ${id} (${title})`,
121	          error,
122	        );
123	      }
124	    }
125	  };
126	
127	  const insertSnippet = () => {
128	    const reference = referenceFor(targetResource);
129	    resolveYaml((resolvedYaml) =>
130	      insertSnippetYaml(id, resolvedYaml, reference),
131	    );
132	  };
133	
134	  const toggleYamlPreview = () => {
135	    setYamlPreviewOpen((open) => !open);
136	    if (!yamlPreview && !yamlPreviewOpen) {
137	      resolveYaml((resolvedYaml) => setYamlPreview(resolvedYaml));
138	    }
139	  };
140	
141	  const { t } = useTranslation('plugin__pipelines-console-plugin');
142	
143	  return (
144	    <li className="co-resource-sidebar-item">
145	      <Title headingLevel="h3" size="lg" className="pf-v6-u-mb-sm">
146	        <span className="pf-v5-u-text-transform-uppercase">
147	          {highlightText}
148	        </span>{' '}
149	        {title}
150	      </Title>
151	      <p>{description}</p>
152	      <Level>
153	        <LevelItem>
154	          <Button type="button" variant="link" isInline onClick={insertSnippet}>
155	            <PasteIcon className="co-icon-space-r" />
156	            {t('Insert snippet')}
157	          </Button>
158	        </LevelItem>
159	        <LevelItem>
160	          <Button
161	            type="button"
162	            variant="link"
163	            isInline
164	            onClick={toggleYamlPreview}
165	          >
166	            {yamlPreviewOpen ? (
167	              <>
168	                {t('Hide YAML')}
169	                <ChevronDownIcon className="co-icon-space-l" />
170	              </>
171	            ) : (
172	              <>
173	                {t('Show YAML')}
174	                <ChevronRightIcon className="co-icon-space-l" />
175	              </>
176	            )}
177	          </Button>
178	        </LevelItem>
179	      </Level>
180	      {yamlPreviewOpen && yamlPreview && <PreviewYAML yaml={yamlPreview} />}
181	    </li>
182	  );
183	};
184	
185	interface ResourceSidebarSnippetsProps {
186	  snippets: Sample[];
187	  insertSnippetYaml(id: string, yaml: string, reference: string);
188	}
189	
190	export const ResourceSidebarSnippets: React.FC<
191	  ResourceSidebarSnippetsProps
192	> = ({ snippets, insertSnippetYaml }) => {
193	  return (
194	    <ul
195	      className="co-resource-sidebar-list"
196	      style={{ listStyle: 'none', paddingLeft: 0 }}
197	    >
198	      {_.map(_.sortBy(snippets, 'title'), (snippet) => (
199	        <ResourceSidebarSnippet
200	          key={snippet.id}
201	          snippet={snippet}
202	          insertSnippetYaml={insertSnippetYaml}
203	        />
204	      ))}
205	    </ul>
206	  );
207	};
208	
209	export const ResourceSidebarSamples: React.FC<ResourceSidebarSamplesProps> = ({
210	  samples,
211	  loadSampleYaml,
212	  downloadSampleYaml,
213	}) => {
214	  return (
215	    <ol className="co-resource-sidebar-list" data-test="resource-samples-list">
216	      {_.map(_.sortBy(samples, 'title'), (sample) => (
217	        <ResourceSidebarSample
218	          key={sample.id}
219	          sample={sample}
220	          loadSampleYaml={loadSampleYaml}
221	          downloadSampleYaml={downloadSampleYaml}
222	        />
223	      ))}
224	    </ol>
225	  );
226	};
