231	  id: string,
232	  yaml: string,
233	  kind: string,
234	) => void;
235	
236	type ResourceSidebarSampleProps = {
237	  sample: Sample;
238	  loadSampleYaml: LoadSampleYaml;
239	  downloadSampleYaml: DownloadSampleYaml;
