241	
242	type ResourceSidebarSamplesProps = {
243	  samples: Sample[];
244	  loadSampleYaml: LoadSampleYaml;
245	  downloadSampleYaml: DownloadSampleYaml;
246	  yamlSamplesList?: FirehoseResult;
247	  kindObj: K8sKind;
248	};

