153	        <LevelItem>
154	          <Button type="button" variant="link" isInline icon={<PasteIcon className="co-icon-space-r" />} onClick={insertSnippet}>
155	            {t('Insert snippet')}
156	          </Button>
157	        </LevelItem>
158	        <LevelItem>
159	          <Button
160	            type="button"
161	            variant="link"
162	            isInline
163	            icon={yamlPreviewOpen ? <ChevronDownIcon className="co-icon-space-l" /> : <ChevronRightIcon className="co-icon-space-l" />}
164	            iconPosition="end"
165	            onClick={toggleYamlPreview}
166	          >
167	            {yamlPreviewOpen ? t('Hide YAML') : t('Show YAML')}
168	          </Button>
169	        </LevelItem>
170	      </Level>
171	      {yamlPreviewOpen && yamlPreview && <PreviewYAML yaml={yamlPreview} />}
172	    </li>
173	  );
